   500→bool CUDAHooks::isGPUArch(const std::vector<std::string>& archs, DeviceIndex device_index) const {
   501→  hipDeviceProp_t* prop;
   502→  if (device_index == -1){
   503→      prop = at::cuda::getCurrentDeviceProperties();
   504→  } else {
   505→      prop = at::cuda::getDeviceProperties(device_index);
   506→  }
   507→
   508→  std::string device_arch = prop->gcnArchName;
   509→  for (std::string arch : archs) {
   510→      size_t substring = device_arch.find(arch);
   511→      if (substring != std::string::npos) {
